    if not os.path.isdir(dir_path):
        return ''
    try:
        # Use absolute path to ls to avoid partial path issues
        result = subprocess.run(
            ['/bin/ls', '-l'],
            cwd=dir_path,
            capture_output=True,
            text=True,
            timeout=10
        )
