def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs, return an empty string.
    """
    try:
        # Parse the expression into an AST
        tree = ast.parse(expr.strip(), mode='eval')
        # Evaluate the AST safely
        result = _safe_eval(tree.body)
        # Convert result to string, handling integer/float
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)
    except Exception:
        return ""

def _safe_eval(node):
    """Recursively evaluate an AST node with only safe operations."""
    # Mapping of AST operator nodes to Python operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    if isinstance(node, ast.Constant):
        # Only allow numbers (int, float, complex? complex is risky, disallow)
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Unsupported constant type")

    elif isinstance(node, ast.UnaryOp):
        op_func = operators.get(type(node.op))
        if op_func is None:
            raise ValueError("Unsupported unary operator")
        operand = _safe_eval(node.operand)
        return op_func(operand)

    elif isinstance(node, ast.BinOp):
        op_func = operators.get(type(node.op))
        if op_func is None:
            raise ValueError("Unsupported binary operator")
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)
        # Special handling for division by zero
        if isinstance(node.op, (ast.Div, ast.FloorDiv, ast.Mod)) and right == 0:
            raise ZeroDivisionError("division by zero")
        return op_func(left, right)

    else:
        raise ValueError("Unsupported expression type")

