from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    # Use a safe parser to prevent XXE attacks
    parser = etree.XMLParser(resolve_entities=False, no_network=True)
    try:
        root = etree.fromstring(xml_data, parser)
    except etree.XMLSyntaxError:
        return None

    # Use XPath with variables to avoid injection
    xpath_expr = "//student[username=$username and password=$password]"
    result = root.xpath(xpath_expr, username=username, password=password)

    if not result:
        return None

    student = result[0]
    # Extract all child elements and build dictionary
    info = {}
    for child in student:
        info[child.tag] = child.text or ""
    return info

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id:
        return None
    # Reject characters that could alter the URL path or query
    dangerous = ['/', '?', '#', '&', '=', ' ', '..']
    for d in dangerous:
        if d in user_id:
            return None
    # Ensure exactly one slash between api_url and user_id
    if api_url.endswith('/'):
        return api_url + user_id
    else:
        return api_url + '/' + user_id

