def confirmAuth(headers):
    try:
        auth_token = headers.get('AuthToken')
        if auth_token is None:
            return None
        decoded = base64.b64decode(auth_token).decode('utf-8')
        token = json.loads(decoded)
        # Check validity of the token object
        if isinstance(token, dict):
            if 'is_valid' in token and token['is_valid']:
                return token.get('data')
            elif 'valid' in token and token['valid']:
                return token.get('data')
            else:
                # Fallback: assume token is valid if it has a 'data' key
                if 'data' in token:
                    return token['data']
        return None
